var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"으으...... 마녀가 되는 것보다 침식체 밥이 되는 게 더 빠를 것 같아......","JPN":"うう……魔女になるより、侵食体の餌になるほうが早そう……","ENG":"Oh no... I think I'll end up getting eaten by a C.O. before I even become a witch...","TWN":"呃呃……看來我還沒成為魔女，就可能先成為侵蝕體的飯菜了……"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"뭘 혼자서 중얼중얼거리는 거야, 견습?","JPN":"何をぶつぶつ呟いてるの、見習い？","ENG":"What are you mumbling about by yourself, newbie?","TWN":"新來的見習生，妳在碎念什麼呢？"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"제법 근성 있는 줄 알았는데 벌써 나자빠진 건 아니지?","JPN":"なかなか根性があると思ったけど、もう弱気になったんじゃないよね？","ENG":"I thought you had some grit. You're not giving up already, are you?","TWN":"還以為妳挺有毅力的，不會這麼快就打退堂鼓了吧？"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그렇지 않아도 온 몸이 쑤셔 죽겠어......","JPN":"ただでさえ全身がズキズキ痛むのに……","ENG":"Actually, I'm already sore all over...","TWN":"渾身酸痛的要命……"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"넌 괜찮아? 여기 온 뒤로 엄청 열심히 싸우고 다녔잖아?","JPN":"あなたは大丈夫ですか？　ここに来てから、ずっと戦ってますよね？","ENG":"Are you okay? You've been fighting so hard since we got down here.","TWN":"妳還好嗎？來到這裡之後妳就一直沒有停止戰鬥。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"당연하지! 이 정도로 약한 소릴 해서는 최강의 마녀가 될 수 없다구!","JPN":"当たり前でしょ！　この程度で弱音を吐いていたら、最強の魔女にはなれないもの！","ENG":"Of course I'm fine! I'll never become the greatest witch if I wimp out now!","TWN":"當然！就這點還難不倒我，不然如何成為最強的魔女呢！"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"최강의 마녀?","JPN":"最強の魔女？","ENG":"The greatest witch?","TWN":"最強的魔女？"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그래. 난 어렸을 때부터 <color=#ffd34c>소녀마녀 네크로노미코</color> 같은 강한 마녀가 되는 게 꿈이었거든.","JPN":"そうよ。私は幼い頃から<color=#ffd34c>魔法少女ネクロノミコ</color>のように強い魔女になることが夢だったの。","ENG":"Yeah. It's always been my dream to become a powerful witch like <color=#ffd34c>Necronomiko the Girl Witch</color>.","TWN":"嗯，我從小的夢想就是成為像<color=#ffd34c>小魔女通靈美子</color>一樣的頂尖魔女。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"뭐, 나도 바보는 아니니까 만화가 현실이 아니라는 것 정도는 알고 있어.","JPN":"まあ、私も漫画と現実が違うってことくらいわかってるよ。","ENG":"Of course, I'm not so stupid to think that an anime is reality.","TWN":"不過我沒傻到把漫畫當作現實。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"원래대로라면 그냥 코스프레 정도로 만족하고 끝났겠지.","JPN":"本来なら、ただコスプレをするくらいで満足していたでしょうね。","ENG":"Normally, I'd probably be satisfied with just a little cosplay.","TWN":"如果是以前，我可能就滿足於扮裝了。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"하지만 보시라! 나도 이렇게 워치를 얻고 카운터가 됐단 말씀!","JPN":"でもほら！　私はウォッチを手に入れてカウンターになったのよ！","ENG":"But behold! I too have earned a Watch and become a Counter!","TWN":"但現在妳看！我成為了擁有能量環的制裁者！"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"이건 나더러 마녀의 길을 걸으라는 하늘의 뜻이 분명하잖아?","JPN":"これは私に魔女の道を歩みなさいという天の啓示でしょ？","ENG":"Surely this is fate's way of telling me to become a witch!","TWN":"這必定是為了讓我成為魔女的天意啊！"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그래서 진짜 마녀가 되려면 어떻게 해야 하는지 이것저것 알아보다가 라우라랑 에블린을 알게 됐어.","JPN":"それで本物の魔女になる方法をあれこれ調べるうちに、ラウラとエヴリンのことを知ったの。","ENG":"And so I dug around for how I could become a real witch. That's when I ran into Laura and Evelyn.","TWN":"就在我為了成為真正的魔女而苦惱的時候，遇到了蘿拉和伊芙琳。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"다짜고짜 승부를 걸었다가 가게를 박살내 버리는 바람에 첫 인상은 영 꽝이었지만......","JPN":"いきなり勝負を申し込んだ上に店をメチャクチャにしたから、\\n第一印象は最悪だったと思うけど……","ENG":"Although I made a terrible first impression because I challenged them to a duel and pretty much destroyed their cafe...","TWN":"我什麼都不管就先打了一架，結果差點把店給毀了，所以給人家的第一印象不怎麼好……"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"어쨌든 지금은 마녀 협회의 일원으로 이렇게 노력하고 있다고!","JPN":"今は魔女協会の一員として努力してるんだから！","ENG":"One way or the other, I ended up becoming a member of the Association! So here I am!","TWN":"但現在我已經成為了魔女協會的一員，並在為此奮鬥！"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"이번에야말로 제일 좋은 재료들을 모아서 그 두 사람이 깜짝 놀랄 만큼 멋진 코스튬을 만들 거야.","JPN":"今回こそ一番良い材料を集めて、あの二人があっと驚くほど素敵なコスチュームを作るのよ。","ENG":"This time, I'll gather the best materials ever to make a costume that will impress even the two of them.","TWN":"這次我一定要集齊最好的材料，做出讓她們兩個大吃一驚的服裝。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그러면 그 까칠한 라우라도 날 정식 마녀로 인정할 수밖에 없겠지! 후후후!","JPN":"そうしたら、あの厳しいラウラも私を正式な魔女として認めるはず！　ふふふ！","ENG":"I'm sure even that grouchy Laura will have to officially recognize me as a witch then! Heh heh!","TWN":"這樣一來，挑剔的蘿拉也只能認可我是正式魔女了！呼呼呼！"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어? 그럼 너도 아직 정식 마녀가 아닌 거야?","JPN":"あれ？　あなたもまだ正式な魔女じゃないんですか？","ENG":"Huh? You mean you're not officially a witch yet?","TWN":"啊？所以妳還不是正式魔女嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};